package weekelyAssignment1;

public class ASCII_Value {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		char value='A';
		int digit=(int)value;
		System.out.println("ASCII value: "+digit);
		
		int New_value= digit + 5;
		System.out.println("New ASCII value: "+New_value);
		
		char c=(char)New_value;
		System.out.println("New character: "+c);
		

	}

}
